import React, { useEffect, useState, useMemo } from "react";
import axios from "axios";

const Summary = () => {
  const [holdings, setHoldings] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  // ==========================
  // Fetch Holdings
  // ==========================
  useEffect(() => {
    const fetchHoldings = async () => {
      try {
        const response = await axios.get(
          `${process.env.REACT_APP_API_URL || "http://localhost:3002"}/allHoldings`
        );

        setHoldings(Array.isArray(response.data) ? response.data : []);
      } catch (err) {
        console.error("Error fetching summary data:", err);
        setError("Failed to load summary data.");
      } finally {
        setLoading(false);
      }
    };

    fetchHoldings();
  }, []);

  // ==========================
  // Filter only owned stocks
  // ==========================
  const ownedStocks = useMemo(() => {
    return holdings.filter(stock => stock.qty && stock.qty > 0);
  }, [holdings]);

  // ==========================
  // Portfolio Calculations
  // ==========================
  const {
    totalInvestment,
    totalCurrentValue,
    totalPnL,
    totalPnLPercent
  } = useMemo(() => {
    const investment = ownedStocks.reduce(
      (acc, stock) => acc + (stock.avg || 0) * (stock.qty || 0),
      0
    );

    const currentValue = ownedStocks.reduce(
      (acc, stock) => acc + (stock.price || 0) * (stock.qty || 0),
      0
    );

    const pnl = currentValue - investment;
    const pnlPercent = investment > 0 ? (pnl / investment) * 100 : 0;

    return {
      totalInvestment: investment,
      totalCurrentValue: currentValue,
      totalPnL: pnl,
      totalPnLPercent: pnlPercent
    };
  }, [ownedStocks]);

  // ==========================
  // Currency Formatter
  // ==========================
  const formatCurrency = (value = 0) =>
    Number(value).toLocaleString("en-IN", {
      minimumFractionDigits: 2,
      maximumFractionDigits: 2,
    });

  if (loading) return <p>Loading summary...</p>;
  if (error) return <p className="error">{error}</p>;

  return (
    <>
      <h3 className="title">Portfolio Summary</h3>

      <div className="summary-container">
        <div className="summary-box">
          <h5>₹{formatCurrency(totalInvestment)}</h5>
          <p>Total Investment</p>
        </div>

        <div className="summary-box">
          <h5>₹{formatCurrency(totalCurrentValue)}</h5>
          <p>Current Value</p>
        </div>

        <div className="summary-box">
          <h5 className={totalPnL >= 0 ? "profit" : "loss"}>
            ₹{formatCurrency(totalPnL)} ({totalPnLPercent.toFixed(2)}%)
          </h5>
          <p>Total P&amp;L</p>
        </div>
      </div>

      {/* Holdings Table */}
      <div className="order-table">
        <table>
          <thead>
            <tr>
              <th>Stock</th>
              <th>Qty</th>
              <th>Avg</th>
              <th>LTP</th>
              <th>P&amp;L</th>
            </tr>
          </thead>

          <tbody>
            {ownedStocks.map((stock, index) => {
              const qty = stock.qty || 0;
              const avg = stock.avg || 0;
              const price = stock.price || 0;
              const pnl = price * qty - avg * qty;

              return (
                <tr key={stock._id || `${stock.name}-${index}`}>
                  <td>{stock.name}</td>
                  <td>{qty}</td>
                  <td>₹{formatCurrency(avg)}</td>
                  <td>₹{formatCurrency(price)}</td>
                  <td className={pnl >= 0 ? "profit" : "loss"}>
                    ₹{formatCurrency(pnl)}
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </>
  );
};

export default Summary;
